#include <bits/stdc++.h>using namespace std;typedef long long ll;int main(){    ll t;    cin>>t;    while(t--){      ll n;      cin>>n;      vector<pair<ll,double>> a(n);      for(int i=0;i<n;i++){        cin>>a[i].first>>a[i].second;        a[i].second=1.0-a[i].second/100.0;      }      vector<double> dp(n,0);      dp[n-1]=a[n-1].first;      for(int i=n-2;i>=0;i--){        dp[i]=max(a[i].first+dp[i+1]*a[i].second, dp[i+1]);      }      cout<<fixed<<setprecision(10)<<dp[0]<<endl;    }}